using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool, Description("Fetches data from an external API by resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to fetch (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompts
{
    [McpServerPrompt, Description("Generates a summarization prompt for any block of text.")]
    public static ChatMessage[] Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Maximum number of sentences in the summary (default: 3).")] int? maxSentences = 3)
    {
        return
        [
            new ChatMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Text = $"""
                        Please summarize the following text in at most {maxSentences ?? 3} sentences.
                        Be concise and capture the key points.

                        ---
                        {text}
                        ---
                        """
                }
            }
        ];
    }
}

